<?php namespace App\Services; use App\Models\Attendance; use App\Models\DailyTimeRecord; use App\Models\Holiday; use App\Models\LeaveRequest; use App\Models\PayrollPeriod; use App\Models\User; use App\Models\CompanySetting; use App\Models\AuditLog; use App\Models\Schedule; use Carbon\Carbon; class DtrService { protected int $swm = 480; protected string $sti = "21:00"; protected string $sto = "06:00"; protected int $gm = 15; protected int $lm = 60; protected int $bm = 30; protected bool $sl = false; public function __construct() {} protected function loadSettings(): void { if ($this->sl) return; $this->swm = CompanySetting::getValue("regular_work_hours", 8) * 60; $this->sti = CompanySetting::getValue("work_start_time", "21:00"); $this->sto = CompanySetting::getValue("work_end_time", "06:00"); $this->gm = CompanySetting::getValue("grace_period_minutes", 15); $this->lm = CompanySetting::getValue("lunch_break_minutes", 60); $this->bm = CompanySetting::getValue("short_break_minutes", 15) * 2; $this->sl = true; } public function getScheduleForEmployee(User $u, ?Carbon $d = null): array { $this->loadSettings(); $d = $d ?? now(); $dn = strtolower($d->format("l")); $sf = $dn . "_schedule"; $ds = ["work_start_time" => $this->sti, "work_end_time" => $this->sto, "work_minutes" => $this->swm, "break_minutes" => $this->lm + $this->bm, "is_rest_day" => false]; if (!empty($u->$sf)) { if (in_array(strtolower(trim($u->$sf)), ["rest day", "off", "restday"])) return array_merge($ds, ["is_rest_day" => true, "work_minutes" => 0]); $p = preg_split("/\s+to\s+|\s+-\s+/i", $u->$sf); if (count($p) === 2) { try { $s = Carbon::parse(trim($p[0])); $e = Carbon::parse(trim($p[1])); if ($e->lt($s)) $e->addDay(); return array_merge($ds, ["work_start_time" => $s->format("H:i"), "work_end_time" => $e->format("H:i"), "work_minutes" => $s->diffInMinutes($e), "break_minutes" => 60]); } catch (\Exception $ex) {} } } if ($u->account_id) { $s = Schedule::where("account_id", $u->account_id)->where("is_active", true)->first(); if ($s) { $st = Carbon::parse($s->work_start_time); $en = Carbon::parse($s->work_end_time); if ($en->lt($st)) $en->addDay(); return array_merge($ds, ["work_start_time" => $s->work_start_time, "work_end_time" => $s->work_end_time, "work_minutes" => $st->diffInMinutes($en), "break_minutes" => $s->break_duration_minutes ?? 60]); } } if ($u->payroll_group_id) { $sh = \App\Models\Shift::where("payroll_group_id", $u->payroll_group_id)->where("category", "Regular/Wholeday")->first(); if ($sh) return array_merge($ds, ["work_start_time" => Carbon::parse($sh->time_in)->format("H:i"), "work_end_time" => Carbon::parse($sh->time_out)->format("H:i"), "work_minutes" => $sh->registered_hours * 60]); } return $ds; } public function generateDtrForPeriod(PayrollPeriod $period, ?array $userIds = null): array { $this->loadSettings(); $start = Carbon::parse($period->start_date); $end = Carbon::parse($period->end_date); $results = ["days_processed" => 0, "total_dtrs_created" => 0, "errors" => []]; while ($start->lte($end)) { $dayResult = $this->generateDtrForDate($start->copy(), (int)$period->id, $userIds); $results["total_dtrs_created"] += $dayResult["created"]; $results["days_processed"]++; $start->addDay(); } return $results; } public function generateDtrForDate(Carbon $d, ?int $p = null, ?array $u = null): array { $this->loadSettings(); $q = User::where("is_active", true); if (!empty($u)) $q->whereIn("id", $u); elseif ($p) { $pe = PayrollPeriod::find((int)$p); if ($pe && $pe->payroll_group_id) $q->where("payroll_group_id", (int)$pe->payroll_group_id); } $es = $q->get(); $rs = ["processed" => 0, "created" => 0, "errors" => []]; foreach ($es as $e) { try { if ($this->generateDtrForEmployee($e, $d, $p)) $rs["created"]++; $rs["processed"]++; } catch (\Exception $ex) { $rs["errors"][] = $ex->getMessage(); } } return $rs; } public function generateDtrForEmployee(User $e, Carbon $d, ?int $p = null): ?DailyTimeRecord { $ex = DailyTimeRecord::where("user_id", (int)$e->id)->whereDate("date", $d->toDateString())->first(); if ($ex && ($ex->status == "approved" || $ex->status == "locked")) return null; $sc = $this->getScheduleForEmployee($e, $d); $at = Attendance::where("user_id", (int)$e->id)->whereDate("date", $d->toDateString())->first(); $da = ["user_id" => (int)$e->id, "payroll_period_id" => (int)$p, "date" => $d->toDateString(), "scheduled_minutes" => (int)$sc["work_minutes"], "status" => "draft", "shift_in" => $sc["work_start_time"], "shift_out" => $sc["work_end_time"], "attendance_status" => ($sc["is_rest_day"] ? "rest_day" : "absent")]; if ($at) { $da["time_in"] = $at->time_in; $da["time_out"] = $at->time_out; $da["attendance_status"] = "present"; $si = Carbon::parse($d->toDateString() . " " . $sc["work_start_time"]); $so = Carbon::parse($d->toDateString() . " " . $sc["work_end_time"]); if ($so->lt($si)) $so->addDay(); $ti = Carbon::parse($at->time_in); $to = $at->time_out ? Carbon::parse($at->time_out) : null; $lt = 0; if ($ti->gt($si->copy()->addMinutes($this->gm))) $lt = $si->diffInMinutes($ti); $ut = 0; if ($to && $to->lt($so)) $ut = $to->diffInMinutes($so); $da["late_minutes"] = $lt; $da["undertime_minutes"] = $ut; $da["actual_work_minutes"] = $ti && $to ? $ti->diffInMinutes($to) : 0; } return DailyTimeRecord::updateOrCreate(["user_id" => (int)$e->id, "date" => $d->toDateString()], $da); } }
